import * as _mergeDeepRight from 'ramda/src/mergeDeepRight';

// hacky fix for jest not importing properly from cjs
const mergeDeepRight = _mergeDeepRight.default || _mergeDeepRight;

/**
 * Takes a map of theme names and their overrides and outputs a similar map with
 * complete themes.
 * NB. themes should contain a `default` property as it is from this that all
 * sibling themes extend
 * @param {object} themes Map of themes
 * @param {string} [baseTheme=default] The key in which the base theme
 * @returns {object} Map of complete theme objects
 */
function buildThemes(themes: { [key: string]: object }, baseTheme = 'base') {
  const defaultTheme = themes[baseTheme] || {};

  return Object.entries(themes)
    .filter(([themeName]) => themeName !== baseTheme)
    .reduce(
      (acc, [themeName, overrides]) => ({
        ...acc,
        [themeName]: mergeDeepRight(defaultTheme, overrides),
      }),
      { ...themes },
    );
}

export default buildThemes;
